from web3 import Web3
from dotenv import load_dotenv
import os

# 🔹 Load env
load_dotenv()

ACCOUNT_ADDRESS = Web3.to_checksum_address(os.getenv("ACCOUNT_ADDRESS"))
PRIVATE_KEY = os.getenv("PRIVATE_KEY")
RPC_URL = os.getenv("RPC_URL")

w3 = Web3(Web3.HTTPProvider(RPC_URL))

if not w3.is_connected():
    raise Exception("❌ Not connected")

print("✅ Connected to Sepolia")
print("💰 Balance:", w3.eth.get_balance(ACCOUNT_ADDRESS)/1e18, "ETH")

# 📜 ABI (PASTE FROM REMIX)
abi = [
    {
        "inputs": [{"internalType": "uint256","name": "_index","type": "uint256"}],
        "name": "vote",
        "outputs": [],
        "stateMutability": "nonpayable",
        "type": "function"
    },
    {
        "inputs": [],
        "name": "getCandidates",
        "outputs": [
            {
                "components": [
                    {"internalType": "string","name": "name","type": "string"},
                    {"internalType": "uint256","name": "voteCount","type": "uint256"}
                ],
                "internalType": "struct Voting.Candidate[]",
                "name": "",
                "type": "tuple[]"
            }
        ],
        "stateMutability": "view",
        "type": "function"
    }
]

# 📦 BYTECODE (PASTE FROM REMIX)
bytecode = ""

# 🚀 DEPLOY
def deploy():
    contract = w3.eth.contract(abi=abi, bytecode=bytecode)

    nonce = w3.eth.get_transaction_count(ACCOUNT_ADDRESS)

    txn = contract.constructor().build_transaction({
        'from': ACCOUNT_ADDRESS,
        'nonce': nonce,
        'gas': 3000000,
        'gasPrice': w3.eth.gas_price
    })

    signed_txn = w3.eth.account.sign_transaction(txn, PRIVATE_KEY)
    tx_hash = w3.eth.send_raw_transaction(signed_txn.raw_transaction)

    print("⛓️ Deploying...")
    receipt = w3.eth.wait_for_transaction_receipt(tx_hash)

    print("✅ Contract deployed:", receipt.contractAddress)
    return receipt.contractAddress

# 🗳️ VOTE
def vote(contract, choice):
    try:
        nonce = w3.eth.get_transaction_count(ACCOUNT_ADDRESS)

        txn = contract.functions.vote(choice).build_transaction({
            'from': ACCOUNT_ADDRESS,
            'nonce': nonce,
            'gas': 200000,
            'gasPrice': w3.eth.gas_price
        })

        signed_txn = w3.eth.account.sign_transaction(txn, PRIVATE_KEY)
        tx_hash = w3.eth.send_raw_transaction(signed_txn.raw_transaction)

        print("⛓️ Voting...")
        receipt = w3.eth.wait_for_transaction_receipt(tx_hash)

        print("✅ Vote success in block:", receipt.blockNumber)

    except Exception as e:
        print("❌ Error:", e)

# 📊 GET RESULT
def get_candidates(contract):
    try:
        candidates = contract.functions.getCandidates().call()

        print("\n🗳️ Results:")
        for c in candidates:
            print(f"{c[0]} → {c[1]} votes")

    except Exception as e:
        print("❌ Fetch error:", e)

# ▶️ MAIN
if __name__ == "__main__":
    print("\n🚀 ADVANCED BLOCKCHAIN VOTING\n")

    contract_address = deploy()
    contract = w3.eth.contract(address=contract_address, abi=abi)

    print("\nChoose candidate:")
    print("0 → Alice")
    print("1 → Bob")

    choice = int(input("👉 Enter your choice: "))

    vote(contract, choice)
    get_candidates(contract)